                        if self._list:
                            msgs = ", ".join(str(x.message) for x in self._list)
                            raise AssertionError(f"{len(self._list)} warning(s) were raised: {msgs}")
                return _NoWarns()
            else:
                if _orig is not None:
                    return _orig(expected_warning, match=match)
                class _WarnsFallback:
                    def __enter__(self):
                        self._cm = warnings.catch_warnings(record=True)
                        self._list = self._cm.__enter__()
                        warnings.simplefilter('always')
                        return self
                    def __exit__(self, exc_type, exc, tb):
                        self._cm.__exit__(exc_type, exc, tb)
                        if expected_warning is not None:
                            found = any(isinstance(x.message, expected_warning) for x in self._list)
                            if not found:
                                raise AssertionError('DID NOT WARN')
                return _WarnsFallback()
